function autoFormatTime(n){let s=n['value']['replace'](/\D/g,'');switch(s['length']>0x4&&(s=s['slice'](0x0,0x4)),s['length']){case 0x0:case 0x1:case 0x2:n['value']=s;break;case 0x3:if(parseInt(s['slice'](0x0,0x2),0xa)<=0x17)n['value']=s['slice'](0x0,0x2)+':'+s['slice'](0x2);else{let T=s['slice'](0x0,0x1)['padStart'](0x2,'0'),q=s['slice'](0x1);n['value']=T+':'+q;}break;case 0x4:let w=s['slice'](0x0,0x2),H=s['slice'](0x2);n['value']=w+':'+H;}}function transformTimeValue(n){let s=n['trim']();if(/^\d{2}$/['test'](s))return s[0x0]['padStart'](0x2,'0')+':'+s[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](s))return 0x3===s['length']?parseInt(s['slice'](0x0,0x2),0xa)<=0x17?s['slice'](0x0,0x2)+':'+s['slice'](0x2):s['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+s['slice'](0x1):s['slice'](0x0,0x2)+':'+s['slice'](0x2);if(s['includes'](':')){let [w,H]=s['split'](':');return H||(H='00'),w=w['padStart'](0x2,'0'),H=H['padStart'](0x2,'0'),w+':'+H;}return s;}